// HMAC-SHA256 validation of the inbound webhook (R-02: fail-closed).
const crypto = require('crypto');
const secret = $env['DESTROY_RESOURCE_WEBHOOK_SECRET'] ?? '';
if (!secret) throw new Error('DESTROY_RESOURCE_WEBHOOK_SECRET missing — fail-closed (R-02)');
const sig = $input.first().headers['x-signature-256'] ?? '';
const rawBody = $input.first().binary?.data?.data
  ? Buffer.from($input.first().binary.data.data, 'base64').toString('utf8')
  : JSON.stringify($input.first().json);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (!sig || sig.length !== expected.length || !crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
  throw new Error('Invalid HMAC — dropping payload (R-02)');
}

// MVP supports railway-service only. Reject other types here so the operator gets a clear 4xx,
// not a misleading approval prompt that would no-op on tap (ADR-0005).
const body = $input.first().json ?? {};
const resource_type = body.resource_type;
const resource_id = body.resource_id;
if (resource_type !== 'railway-service') throw new Error('Unsupported resource_type — MVP only accepts "railway-service" (ADR-0005)');
if (!resource_id || typeof resource_id !== 'string') throw new Error('Missing or non-string resource_id');
// callback_data budget: 64 bytes total, prefix "dr:a:rs:" = 8 bytes → 56-byte ceiling on resource_id.
if (resource_id.length > 48) throw new Error('resource_id exceeds 48-char callback_data budget');
const reason = typeof body.reason === 'string' ? body.reason : '';
const chat_id = body.chat_id ? String(body.chat_id) : '';

return [{
  json: {
    intent: 'destroy delete remove drop terminate ' + resource_type + ' ' + resource_id,
    chat_id,
    user_id: String(body.user_id ?? ''),
    timestamp: new Date().toISOString(),
    metadata: { resource_type, resource_id, reason }
  }
}];

// HMAC-SHA256 over the exact body string the Router will read (ADR-0003).
const crypto = require('crypto');
const p = $input.first().json;
const bodyObj = {
  intent: p.intent,
  chat_id: p.chat_id,
  user_id: p.user_id,
  timestamp: p.timestamp,
  metadata: p.metadata,
};
const bodyStr = JSON.stringify(bodyObj);
const secret = $env['SKILLS_ROUTER_SECRET'] ?? '';
if (!secret) throw new Error('SKILLS_ROUTER_SECRET missing — fail-closed (R-02)');
const sig = 'sha256=' + crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
return [{ json: { _bodyStr: bodyStr, _sig: sig, _chat_id: p.chat_id, _meta: p.metadata } }];

// Build the Telegram approval prompt. Operator taps either button; approval-callback.json (ADR-0005) parses
// the callback_data and routes to the destroy API. callback_data budget is 64 bytes; prefix "dr:a:rs:" = 8 bytes.
const meta = $('Compute Skills Router HMAC').first().json._meta;
const chat_id = $('Compute Skills Router HMAC').first().json._chat_id || $env['TELEGRAM_CHAT_ID'] || '';
const id = meta.resource_id;
const reason = meta.reason || '(no reason given)';
const text = '🚨 Destroy resource?\nType: ' + meta.resource_type + '\nID: ' + id + '\nReason: ' + reason + '\n\nTap a button to confirm.';
const approve_data = 'dr:a:rs:' + id;
const deny_data = 'dr:d:rs:' + id;
const reply_markup = { inline_keyboard: [[ { text: '✅ Approve', callback_data: approve_data }, { text: '❌ Deny', callback_data: deny_data } ]] };
return [{ json: { chat_id, text, reply_markup } }];

const r = $input.first().json;
const chat_id = $('Compute Skills Router HMAC').first().json._chat_id;
let reason;
if (r?.matched === false) {
  reason = 'no skill matched';
} else if (r?.skill && r.skill !== 'destroy-resource') {
  reason = 'router routed to a different skill: ' + r.skill;
} else if (r?.status && r.status !== 'pending_approval') {
  reason = 'router returned unexpected status: ' + r.status;
} else {
  reason = 'unexpected router response';
}
return [{ json: { chat_id, text: 'Destroy approval prompt not sent — ' + reason } }];
